import json,re,statistics as st
def spread(f, pat=r'\[\[?(\d+)\]'):
    rows=[json.loads(l) for l in open(f)]
    cors=[];firstsec_range=[]
    for r in rows:
        a=r['article']
        hits=[(m.start()/len(a), int(m.group(1))) for m in re.finditer(pat,a)]
        hits=[h for h in hits if h[1]<1000]
        if len(hits)<20: continue
        xs=[h[0] for h in hits]; ys=[h[1] for h in hits]
        mx,my=st.mean(xs),st.mean(ys)
        num=sum((x-mx)*(y-my) for x,y in hits)
        den=(sum((x-mx)**2 for x in xs)*sum((y-my)**2 for y in ys))**.5
        if den: cors.append(num/den)
        # in first 20% of doc, what fraction of the report's full index range is used?
        early=[y for x,y in hits if x<0.2]
        if early and max(ys)>1: firstsec_range.append((max(early)-min(early))/(max(ys)-min(ys)+1e-9))
    return round(st.mean(cors),3), len(cors), round(st.mean(firstsec_range),2)
for f in ['bodhi.jsonl','cellcog-max.jsonl','WhaleCloud-DocChain_0612.jsonl','gemini-2.5-pro-deepresearch.jsonl','openai-deepresearch.jsonl','lunon_full100_FINAL.submission.jsonl','sourcery.jsonl']:
    try:
        c,n,fr=spread(f)
        print(f'{f:40s} corr(position, cite_index)={c:+.3f}  n={n}  frac_of_index_range_used_in_first20%={fr}')
    except Exception as e: print(f,'ERR',e)
