import json,re,statistics as st
arts={json.loads(l)['id']:json.loads(l)['article'] for l in open('bodhi.jsonl')}
sc={json.loads(l)['id']:json.loads(l) for l in open('scores/bodhi/raw_results.jsonl')}
IMPL=re.compile(r'(implication|含义|启示|意味着|机制|解读|判断|why|为什么|takeaway|结论|net effect|interpretation)',re.I)
def feats(a):
    lines=a.split(chr(10))
    inf=sum(1 for l in lines if re.match(r'\s*[-*]?\s*\*\*[^*\n]{2,60}\*\*\s*[:：]',l) and IMPL.search(l.split('**')[1]) and '[[' not in l)
    return dict(loglen=len(a)**.5, h3=len(re.findall(r'^###',a,re.M)), cites=len(re.findall(r'\[\[\d+\]\]',a)),
      uniq=len(set(re.findall(r'\]\((https?://[^)]+)\)',a))), infer_lines=inf, tables=len(re.findall(r'^\|',a,re.M)),
      bold=len(re.findall(r'\*\*',a))/2, citedens=len(re.findall(r'\[\[\d+\]\]',a))/max(len(a),1)*1000)
def corr(x,y):
    mx,my=st.mean(x),st.mean(y)
    n=sum((a-mx)*(b-my) for a,b in zip(x,y)); d=(sum((a-mx)**2 for a in x)*sum((b-my)**2 for b in y))**.5
    return n/d if d else 0
ids=sorted(arts)
F={k:[feats(arts[i])[k] for i in ids] for k in feats(arts[ids[0]])}
for dim in ['insight','comprehensiveness','instruction_following','readability','overall_score']:
    y=[sc[i][dim] for i in ids]
    print(dim, ' '.join(f'{k}={corr(F[k],y):+.2f}' for k in F))
print()
print('bodhi insight  mean',round(st.mean([sc[i][\"insight\"] for i in ids]),4),'min',round(min(sc[i][\"insight\"] for i in ids),3),'max',round(max(sc[i][\"insight\"] for i in ids),3))
